552ŌåÆexport interface SpawnOptions {
553ŌåÆ  timeout: number;
554ŌåÆ  env?: NodeJS.ProcessEnv;
555ŌåÆ  signal?: AbortSignal;
556ŌåÆ  /** Called with each stderr chunk (real-time, before process exits) */
557ŌåÆ  onStderr?: (chunk: string) => void;
558ŌåÆ  /** Called with each stdout chunk (real-time, before process exits) */
559ŌåÆ  onStdout?: (chunk: string) => void;
