562ŌåÆ/** @internal Exported for testing only */
563ŌåÆexport function spawnAsync(
564ŌåÆ  command: string,
565ŌåÆ  args: string[],
566ŌåÆ  options: SpawnOptions,
567ŌåÆ): Promise<SpawnResult> {
568ŌåÆ  return new Promise((resolve, reject) => {
569ŌåÆ    let stdout = "";
570ŌåÆ    let stderr = "";
571ŌåÆ    let settled = false;
572ŌåÆ
573ŌåÆ    const proc = spawn(command, args, {
574ŌåÆ      stdio: ["pipe", "pipe", "pipe"],
575ŌåÆ      env: options.env,
576ŌåÆ      detached: true,
577ŌåÆ    });
578ŌåÆ
579ŌåÆ    const settle = (
580ŌåÆ      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
581ŌåÆ    ) => {
582ŌåÆ      if (settled) return;
583ŌåÆ      settled = true;
584ŌåÆ      clearTimeout(timeoutId);
585ŌåÆ      options.signal?.removeEventListener("abort", onAbort);
586ŌåÆ      if (outcome.ok) {
587ŌåÆ        resolve(outcome.result);
588ŌåÆ      } else {
589ŌåÆ        reject(outcome.error);
590ŌåÆ      }
591ŌåÆ    };
592ŌåÆ
593ŌåÆ    const timeoutId = setTimeout(() => {
594ŌåÆ      killProcessGroup(proc);
595ŌåÆ      settle({
596ŌåÆ        ok: false,
597ŌåÆ        error: new Error(`Process timed out after ${options.timeout}ms`),
598ŌåÆ      });
599ŌåÆ    }, options.timeout);
600ŌåÆ
601ŌåÆ    const onAbort = () => {
602ŌåÆ      killProcessGroup(proc);
603ŌåÆ      settle({ ok: false, error: new Error("Cancelled by client") });
604ŌåÆ    };
605ŌåÆ
606ŌåÆ    if (options.signal) {
607ŌåÆ      if (options.signal.aborted) {
608ŌåÆ        killProcessGroup(proc);
609ŌåÆ        clearTimeout(timeoutId);
610ŌåÆ        reject(new Error("Cancelled by client"));
611ŌåÆ        return;
612ŌåÆ      }
613ŌåÆ      options.signal.addEventListener("abort", onAbort, { once: true });
614ŌåÆ    }
615ŌåÆ
616ŌåÆ    proc.stdout.on("data", (data: Buffer) => {
617ŌåÆ      const chunk = data.toString();
618ŌåÆ      stdout += chunk;
619ŌåÆ      options.onStdout?.(chunk);
620ŌåÆ    });
621ŌåÆ
622ŌåÆ    proc.stderr.on("data", (data: Buffer) => {
623ŌåÆ      const chunk = data.toString();
624ŌåÆ      stderr += chunk;
625ŌåÆ      options.onStderr?.(chunk);
626ŌåÆ    });
627ŌåÆ
628ŌåÆ    proc.on("error", (err: NodeJS.ErrnoException) => {
629ŌåÆ      if (err.code === "ENOENT") {
630ŌåÆ        settle({
631ŌåÆ          ok: false,
632ŌåÆ          error: new Error(
633ŌåÆ            `Command not found: ${command}. Ensure it is installed and in PATH.`,
634ŌåÆ          ),
635ŌåÆ        });
636ŌåÆ      } else {
637ŌåÆ        settle({
638ŌåÆ          ok: false,
639ŌåÆ          error: new Error(`Failed to spawn process: ${err.message}`),
640ŌåÆ        });
641ŌåÆ      }
642ŌåÆ    });
643ŌåÆ
644ŌåÆ    proc.on("close", (code: number | null) => {
645ŌåÆ      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
646ŌåÆ    });
647ŌåÆ  });
648ŌåÆ}
649ŌåÆ
650ŌåÆconst SIGKILL_GRACE_MS = 5000;
651ŌåÆ
652ŌåÆfunction killProcessGroup(proc: ReturnType<typeof spawn>): void {
653ŌåÆ  let exited = false;
654ŌåÆ  proc.on("close", () => {
655ŌåÆ    exited = true;
656ŌåÆ  });
657ŌåÆ
658ŌåÆ  sendSignal(proc, "SIGTERM");
659ŌåÆ
660ŌåÆ  setTimeout(() => {
661ŌåÆ    if (!exited) {
662ŌåÆ      sendSignal(proc, "SIGKILL");
663ŌåÆ    }
664ŌåÆ  }, SIGKILL_GRACE_MS).unref();
665ŌåÆ}
