667ŌåÆfunction sendSignal(
668ŌåÆ  proc: ReturnType<typeof spawn>,
669ŌåÆ  signal: NodeJS.Signals,
670ŌåÆ): void {
671ŌåÆ  try {
672ŌåÆ    if (proc.pid) {
673ŌåÆ      process.kill(-proc.pid, signal);
674ŌåÆ    }
675ŌåÆ  } catch {
676ŌåÆ    // Process group may already be gone ŌĆö fall back to direct kill
677ŌåÆ    if (!proc.killed) {
678ŌåÆ      proc.kill(signal);
679ŌåÆ    }
680ŌåÆ  }
681ŌåÆ}
