212ŌåÆexport function sortByDependencies(issueNumbers: number[]): number[] {
213ŌåÆ  // Build dependency graph
214ŌåÆ  const dependsOn = new Map<number, number[]>();
215ŌåÆ  for (const issue of issueNumbers) {
