221ŌåÆ    );
222ŌåÆ  }
223ŌåÆ
224ŌåÆ  // Topological sort using Kahn's algorithm
225ŌåÆ  const inDegree = new Map<number, number>();
226ŌåÆ  for (const issue of issueNumbers) {
227ŌåÆ    inDegree.set(issue, 0);
228ŌåÆ  }
229ŌåÆ  for (const deps of dependsOn.values()) {
230ŌåÆ    for (const dep of deps) {
231ŌåÆ      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
232ŌåÆ    }
233ŌåÆ  }
234ŌåÆ
235ŌåÆ  // Note: inDegree counts how many issues depend on each issue
236ŌåÆ  // We want to process issues that have no dependencies first,
237ŌåÆ  // so dependent issues come after their prerequisites
238ŌåÆ  const sorted: number[] = [];
239ŌåÆ  const queue: number[] = [];
240ŌåÆ
241ŌåÆ  // Start with issues that have no dependencies
242ŌåÆ  for (const issue of issueNumbers) {
243ŌåÆ    const deps = dependsOn.get(issue) || [];
244ŌåÆ    if (deps.length === 0) {
245ŌåÆ      queue.push(issue);
246ŌåÆ    }
247ŌåÆ  }
248ŌåÆ
249ŌåÆ  const visited = new Set<number>();
250ŌåÆ  while (queue.length > 0) {
251ŌåÆ    const issue = queue.shift()!;
252ŌåÆ    if (visited.has(issue)) continue;
253ŌåÆ    visited.add(issue);
254ŌåÆ    sorted.push(issue);
255ŌåÆ
256ŌåÆ    // Find issues that depend on this one
257ŌåÆ    for (const [other, deps] of dependsOn.entries()) {
258ŌåÆ      if (deps.includes(issue) && !visited.has(other)) {
259ŌåÆ        // Check if all dependencies of 'other' are satisfied
260ŌåÆ        const allDepsSatisfied = deps.every((d) => visited.has(d));
261ŌåÆ        if (allDepsSatisfied) {
262ŌåÆ          queue.push(other);
263ŌåÆ        }
264ŌåÆ      }
265ŌåÆ    }
266ŌåÆ  }
267ŌåÆ
268ŌåÆ  // Add any remaining issues (circular dependencies or unvisited)
269ŌåÆ  for (const issue of issueNumbers) {
270ŌåÆ    if (!visited.has(issue)) {
271ŌåÆ      sorted.push(issue);
272ŌåÆ    }
273ŌåÆ  }
274ŌåÆ
275ŌåÆ  return sorted;
276ŌåÆ}
