423ŌåÆ        // Update worktree info if it changed
424ŌåÆ        if (worktreePath && branch) {
425ŌåÆ          await stateManager.updateWorktreeInfo(
426ŌåÆ            issueNumber,
427ŌåÆ            worktreePath,
428ŌåÆ            branch,
429ŌåÆ          );
430ŌåÆ        }
431ŌåÆ      }
432ŌåÆ    } catch (error) {
433ŌåÆ      // State tracking errors shouldn't stop execution
434ŌåÆ      if (config.verbose) {
435ŌåÆ        log(chalk.yellow(`    ŌÜĀ’ĖÅ  State tracking error: ${error}`));
436ŌåÆ      }
437ŌåÆ    }
438ŌåÆ  }
439ŌåÆ
440ŌåÆ  // Determine phases for this specific issue
441ŌåÆ  let phases: Phase[];
442ŌåÆ  let detectedQualityLoop = false;
443ŌåÆ  let specAlreadyRan = false;
444ŌåÆ
445ŌåÆ  if (options.autoDetectPhases) {
446ŌåÆ    // Check if labels indicate a simple bug/fix (skip spec entirely)
447ŌåÆ    const lowerLabels = labels.map((l) => l.toLowerCase());
448ŌåÆ    const isSimpleBugFix = lowerLabels.some((label) =>
449ŌåÆ      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
450ŌåÆ    );
451ŌåÆ
452ŌåÆ    if (isSimpleBugFix) {
453ŌåÆ      // Simple bug fix: skip spec, go straight to exec ŌåÆ qa
454ŌåÆ      phases = ["exec", "qa"];
455ŌåÆ      log(chalk.gray(`    Bug fix detected: ${phases.join(" ŌåÆ ")}`));
456ŌåÆ    } else {
457ŌåÆ      // Run spec first to get recommended workflow
458ŌåÆ      log(chalk.gray(`    Running spec to determine workflow...`));
459ŌåÆ
460ŌåÆ      // Create spinner for spec phase (suppressed in parallel mode to prevent interleaving)
461ŌåÆ      const specSpinner = config.parallel
462ŌåÆ        ? undefined
463ŌåÆ        : new PhaseSpinner({
464ŌåÆ            phase: "spec",
465ŌåÆ            phaseIndex: 1,
466ŌåÆ            totalPhases: 3, // Estimate; will be refined after spec
467ŌåÆ            shutdownManager,
468ŌåÆ          });
469ŌåÆ      specSpinner?.start();
470ŌåÆ      emitProgressLine(issueNumber, "spec");
471ŌåÆ
472ŌåÆ      // Track spec phase start in state
473ŌåÆ      if (stateManager) {
474ŌåÆ        try {
475ŌåÆ          await stateManager.updatePhaseStatus(
476ŌåÆ            issueNumber,
477ŌåÆ            "spec",
478ŌåÆ            "in_progress",
479ŌåÆ          );
480ŌåÆ        } catch {
481ŌåÆ          // State tracking errors shouldn't stop execution
482ŌåÆ        }
483ŌåÆ      }
484ŌåÆ
485ŌåÆ      const specStartTime = new Date();
486ŌåÆ      // Note: spec runs in main repo (not worktree) for planning
487ŌåÆ      const specResult = await executePhaseWithRetry(
488ŌåÆ        issueNumber,
489ŌåÆ        "spec",
490ŌåÆ        config,
491ŌåÆ        sessionId,
492ŌåÆ        worktreePath, // Will be ignored for spec (non-isolated phase)
493ŌåÆ        shutdownManager,
494ŌåÆ        specSpinner,
495ŌåÆ      );
496ŌåÆ      const specEndTime = new Date();
497ŌåÆ
498ŌåÆ      if (specResult.sessionId) {
499ŌåÆ        sessionId = specResult.sessionId;
500ŌåÆ        // Update session ID in state for resume capability
501ŌåÆ        if (stateManager) {
502ŌåÆ          try {
503ŌåÆ            await stateManager.updateSessionId(
504ŌåÆ              issueNumber,
505ŌåÆ              specResult.sessionId,
506ŌåÆ            );
507ŌåÆ          } catch {
508ŌåÆ            // State tracking errors shouldn't stop execution
509ŌåÆ          }
510ŌåÆ        }
511ŌåÆ      }
512ŌåÆ
513ŌåÆ      phaseResults.push(specResult);
514ŌåÆ      specAlreadyRan = true;
515ŌåÆ
516ŌåÆ      // Log spec phase result
517ŌåÆ      // Note: Spec runs in main repo, not worktree, so no git diff stats
518ŌåÆ      if (logWriter) {
519ŌåÆ        const phaseLog = createPhaseLogFromTiming(
520ŌåÆ          "spec",
521ŌåÆ          issueNumber,
522ŌåÆ          specStartTime,
523ŌåÆ          specEndTime,
524ŌåÆ          specResult.success
525ŌåÆ            ? "success"
526ŌåÆ            : specResult.error?.includes("Timeout")
527ŌåÆ              ? "timeout"
528ŌåÆ              : "failure",
529ŌåÆ          { error: specResult.error },
530ŌåÆ        );
531ŌåÆ        logWriter.logPhase(phaseLog);
532ŌåÆ      }
533ŌåÆ
534ŌåÆ      // Track spec phase completion in state
535ŌåÆ      if (stateManager) {
536ŌåÆ        try {
537ŌåÆ          const phaseStatus = specResult.success ? "completed" : "failed";
538ŌåÆ          await stateManager.updatePhaseStatus(
539ŌåÆ            issueNumber,
540ŌåÆ            "spec",
541ŌåÆ            phaseStatus,
542ŌåÆ            {
543ŌåÆ              error: specResult.error,
544ŌåÆ            },
545ŌåÆ          );
546ŌåÆ        } catch {
547ŌåÆ          // State tracking errors shouldn't stop execution
548ŌåÆ        }
549ŌåÆ      }
550ŌåÆ
551ŌåÆ      if (!specResult.success) {
552ŌåÆ        specSpinner?.fail(specResult.error);
553ŌåÆ        const durationSeconds = (Date.now() - startTime) / 1000;
554ŌåÆ        return {
555ŌåÆ          issueNumber,
556ŌåÆ          success: false,
557ŌåÆ          phaseResults,
558ŌåÆ          durationSeconds,
559ŌåÆ          loopTriggered: false,
560ŌåÆ        };
561ŌåÆ      }
562ŌåÆ
563ŌåÆ      specSpinner?.succeed();
564ŌåÆ
565ŌåÆ      // Parse recommended workflow from spec output
566ŌåÆ      const parsedWorkflow = specResult.output
567ŌåÆ        ? parseRecommendedWorkflow(specResult.output)
568ŌåÆ        : null;
569ŌåÆ
570ŌåÆ      if (parsedWorkflow) {
571ŌåÆ        // Remove spec from phases since we already ran it
572ŌåÆ        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
573ŌåÆ        detectedQualityLoop = parsedWorkflow.qualityLoop;
574ŌåÆ        log(
575ŌåÆ          chalk.gray(
576ŌåÆ            `    Spec recommends: ${phases.join(" ŌåÆ ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
577ŌåÆ          ),
578ŌåÆ        );
579ŌåÆ      } else {
580ŌåÆ        // Fall back to label-based detection
581ŌåÆ        log(
582ŌåÆ          chalk.yellow(
583ŌåÆ            `    Could not parse spec recommendation, using label-based detection`,
584ŌåÆ          ),
585ŌåÆ        );
586ŌåÆ        const detected = detectPhasesFromLabels(labels);
587ŌåÆ        phases = detected.phases.filter((p) => p !== "spec");
588ŌåÆ        detectedQualityLoop = detected.qualityLoop;
589ŌåÆ        log(chalk.gray(`    Fallback: ${phases.join(" ŌåÆ ")}`));
590ŌåÆ      }
591ŌåÆ    }
592ŌåÆ  } else {
593ŌåÆ    // Use explicit phases with adjustments
594ŌåÆ    phases = determinePhasesForIssue(config.phases, labels, options);
595ŌåÆ    if (phases.length !== config.phases.length) {
596ŌåÆ      log(chalk.gray(`    Phases adjusted: ${phases.join(" ŌåÆ ")}`));
597ŌåÆ    }
598ŌåÆ  }
599ŌåÆ
600ŌåÆ  // Resume: filter out completed phases if --resume flag is set
601ŌåÆ  if (options.resume) {
602ŌåÆ    const resumeResult = filterResumedPhases(issueNumber, phases, true);
603ŌåÆ    if (resumeResult.skipped.length > 0) {
604ŌåÆ      log(
605ŌåÆ        chalk.gray(
606ŌåÆ          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
607ŌåÆ        ),
608ŌåÆ      );
609ŌåÆ      phases = resumeResult.phases;
610ŌåÆ    }
611ŌåÆ    // Also skip spec if it was auto-detected as completed
612ŌåÆ    if (
613ŌåÆ      specAlreadyRan &&
614ŌåÆ      resumeResult.skipped.length === 0 &&
615ŌåÆ      resumeResult.phases.length === 0
616ŌåÆ    ) {
617ŌåÆ      log(chalk.gray(`    Resume: all phases already completed`));
618ŌåÆ    }
619ŌåÆ  }
620ŌåÆ
621ŌåÆ  // Add testgen phase if requested (and spec was in the phases)
622ŌåÆ  if (
623ŌåÆ    options.testgen &&
624ŌåÆ    (phases.includes("spec") || specAlreadyRan) &&
625ŌåÆ    !phases.includes("testgen")
626ŌåÆ  ) {
627ŌåÆ    // Insert testgen at the beginning if spec already ran, otherwise after spec
628ŌåÆ    if (specAlreadyRan) {
629ŌåÆ      phases.unshift("testgen");
630ŌåÆ    } else {
631ŌåÆ      const specIndex = phases.indexOf("spec");
632ŌåÆ      if (specIndex !== -1) {
633ŌåÆ        phases.splice(specIndex + 1, 0, "testgen");
634ŌåÆ      }
635ŌåÆ    }
636ŌåÆ  }
637ŌåÆ
638ŌåÆ  let iteration = 0;
639ŌåÆ  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
640ŌåÆ  const maxIterations = useQualityLoop ? config.maxIterations : 1;
641ŌåÆ  let completedSuccessfully = false;
642ŌåÆ
643ŌåÆ  while (iteration < maxIterations) {
644ŌåÆ    iteration++;
645ŌåÆ
646ŌåÆ    if (useQualityLoop && iteration > 1) {
647ŌåÆ      log(
648ŌåÆ        chalk.yellow(
649ŌåÆ          `    Quality loop iteration ${iteration}/${maxIterations}`,
650ŌåÆ        ),
651ŌåÆ      );
652ŌåÆ      loopTriggered = true;
653ŌåÆ    }
654ŌåÆ
655ŌåÆ    let phasesFailed = false;
656ŌåÆ
657ŌåÆ    // Calculate total phases for progress indicator
658ŌåÆ    // If spec already ran in auto-detect mode, it's counted separately
659ŌåÆ    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
660ŌåÆ    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
661ŌåÆ
662ŌåÆ    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
663ŌåÆ      const phase = phases[phaseIdx];
664ŌåÆ      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
665ŌåÆ
666ŌåÆ      // Create spinner for this phase (suppressed in parallel mode)
667ŌåÆ      const phaseSpinner = config.parallel
668ŌåÆ        ? undefined
669ŌåÆ        : new PhaseSpinner({
670ŌåÆ            phase,
671ŌåÆ            phaseIndex: phaseNumber,
672ŌåÆ            totalPhases,
673ŌåÆ            shutdownManager,
674ŌåÆ            iteration: useQualityLoop ? iteration : undefined,
675ŌåÆ          });
676ŌåÆ      phaseSpinner?.start();
677ŌåÆ      emitProgressLine(issueNumber, phase);
678ŌåÆ
679ŌåÆ      // Track phase start in state
680ŌåÆ      if (stateManager) {
681ŌåÆ        try {
682ŌåÆ          await stateManager.updatePhaseStatus(
683ŌåÆ            issueNumber,
684ŌåÆ            phase as Phase,
685ŌåÆ            "in_progress",
686ŌåÆ          );
687ŌåÆ        } catch {
688ŌåÆ          // State tracking errors shouldn't stop execution
689ŌåÆ        }
690ŌåÆ      }
691ŌåÆ
692ŌåÆ      const phaseStartTime = new Date();
693ŌåÆ      const result = await executePhaseWithRetry(
694ŌåÆ        issueNumber,
695ŌåÆ        phase,
696ŌåÆ        config,
697ŌåÆ        sessionId,
698ŌåÆ        worktreePath,
699ŌåÆ        shutdownManager,
700ŌåÆ        phaseSpinner,
701ŌåÆ      );
702ŌåÆ      const phaseEndTime = new Date();
703ŌåÆ
704ŌåÆ      // Capture session ID for subsequent phases
705ŌåÆ      if (result.sessionId) {
706ŌåÆ        sessionId = result.sessionId;
707ŌåÆ        // Update session ID in state for resume capability
708ŌåÆ        if (stateManager) {
709ŌåÆ          try {
710ŌåÆ            await stateManager.updateSessionId(issueNumber, result.sessionId);
711ŌåÆ          } catch {
712ŌåÆ            // State tracking errors shouldn't stop execution
713ŌåÆ          }
714ŌåÆ        }
715ŌåÆ      }
716ŌåÆ
717ŌåÆ      phaseResults.push(result);
718ŌåÆ
719ŌåÆ      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
720ŌåÆ      if (logWriter) {
721ŌåÆ        // Capture git diff stats for worktree phases (AC-1, AC-3)
722ŌåÆ        const diffStats = worktreePath
723ŌåÆ          ? getGitDiffStats(worktreePath, baseBranch)
724ŌåÆ          : undefined;
725ŌåÆ
726ŌåÆ        // Capture commit hash after phase (AC-2)
727ŌåÆ        const commitHash = worktreePath
728ŌåÆ          ? getCommitHash(worktreePath)
729ŌåÆ          : undefined;
730ŌåÆ
731ŌåÆ        // Read cache metrics for QA phase (AC-7)
732ŌåÆ        const cacheMetrics =
733ŌåÆ          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
734ŌåÆ
735ŌåÆ        const phaseLog = createPhaseLogFromTiming(
736ŌåÆ          phase,
737ŌåÆ          issueNumber,
738ŌåÆ          phaseStartTime,
739ŌåÆ          phaseEndTime,
740ŌåÆ          result.success
741ŌåÆ            ? "success"
742ŌåÆ            : result.error?.includes("Timeout")
743ŌåÆ              ? "timeout"
744ŌåÆ              : "failure",
745ŌåÆ          {
746ŌåÆ            error: result.error,
747ŌåÆ            verdict: result.verdict,
748ŌåÆ            // Observability fields (AC-1, AC-2, AC-3, AC-7)
749ŌåÆ            filesModified: diffStats?.filesModified,
750ŌåÆ            fileDiffStats: diffStats?.fileDiffStats,
751ŌåÆ            commitHash,
752ŌåÆ            cacheMetrics,
753ŌåÆ          },
754ŌåÆ        );
755ŌåÆ        logWriter.logPhase(phaseLog);
756ŌåÆ      }
757ŌåÆ
758ŌåÆ      // Track phase completion in state
759ŌåÆ      if (stateManager) {
760ŌåÆ        try {
761ŌåÆ          const phaseStatus = result.success
762ŌåÆ            ? "completed"
763ŌåÆ            : result.error?.includes("Timeout")
764ŌåÆ              ? "failed"
765ŌåÆ              : "failed";
766ŌåÆ          await stateManager.updatePhaseStatus(
767ŌåÆ            issueNumber,
768ŌåÆ            phase as Phase,
769ŌåÆ            phaseStatus,
770ŌåÆ            { error: result.error },
771ŌåÆ          );
772ŌåÆ        } catch {
773ŌåÆ          // State tracking errors shouldn't stop execution
774ŌåÆ        }
775ŌåÆ      }
776ŌåÆ
777ŌåÆ      if (result.success) {
778ŌåÆ        phaseSpinner?.succeed();
779ŌåÆ      } else {
780ŌåÆ        phaseSpinner?.fail(result.error);
781ŌåÆ        phasesFailed = true;
782ŌåÆ
783ŌåÆ        // If quality loop enabled, run loop phase to fix issues
784ŌåÆ        if (useQualityLoop && iteration < maxIterations) {
785ŌåÆ          // Create spinner for loop phase (suppressed in parallel mode)
786ŌåÆ          const loopSpinner = config.parallel
787ŌåÆ            ? undefined
788ŌåÆ            : new PhaseSpinner({
789ŌåÆ                phase: "loop",
790ŌåÆ                phaseIndex: phaseNumber,
791ŌåÆ                totalPhases,
792ŌåÆ                shutdownManager,
793ŌåÆ                iteration,
794ŌåÆ              });
795ŌåÆ          loopSpinner?.start();
796ŌåÆ          emitProgressLine(issueNumber, "loop");
797ŌåÆ
798ŌåÆ          const loopResult = await executePhaseWithRetry(
799ŌåÆ            issueNumber,
800ŌåÆ            "loop",
801ŌåÆ            config,
802ŌåÆ            sessionId,
803ŌåÆ            worktreePath,
804ŌåÆ            shutdownManager,
805ŌåÆ            loopSpinner,
806ŌåÆ          );
807ŌåÆ          phaseResults.push(loopResult);
808ŌåÆ
809ŌåÆ          if (loopResult.sessionId) {
810ŌåÆ            sessionId = loopResult.sessionId;
811ŌåÆ          }
812ŌåÆ
813ŌåÆ          if (loopResult.success) {
814ŌåÆ            loopSpinner?.succeed();
815ŌåÆ            // Continue to next iteration
816ŌåÆ            break;
817ŌåÆ          } else {
818ŌåÆ            loopSpinner?.fail(loopResult.error);
819ŌåÆ          }
820ŌåÆ        }
821ŌåÆ
822ŌåÆ        // Stop on first failure (if not in quality loop or loop failed)
823ŌåÆ        break;
824ŌåÆ      }
825ŌåÆ    }
826ŌåÆ
827ŌåÆ    // If all phases passed, exit the loop
828ŌåÆ    if (!phasesFailed) {
829ŌåÆ      completedSuccessfully = true;
830ŌåÆ      break;
831ŌåÆ    }
832ŌåÆ
833ŌåÆ    // If we're not in quality loop mode, don't retry
834ŌåÆ    if (!config.qualityLoop) {
835ŌåÆ      break;
836ŌåÆ    }
837ŌåÆ  }
838ŌåÆ
839ŌåÆ  const durationSeconds = (Date.now() - startTime) / 1000;
840ŌåÆ  // Success is determined by whether all phases completed in any iteration,
841ŌåÆ  // not whether all accumulated phase results passed (which would fail after loop recovery)
842ŌåÆ  const success = completedSuccessfully;
843ŌåÆ
844ŌåÆ  // Update final issue status in state
845ŌåÆ  if (stateManager) {
846ŌåÆ    try {
847ŌåÆ      const finalStatus = success ? "ready_for_merge" : "in_progress";
848ŌåÆ      await stateManager.updateIssueStatus(issueNumber, finalStatus);
849ŌåÆ    } catch {
850ŌåÆ      // State tracking errors shouldn't stop execution
851ŌåÆ    }
852ŌåÆ  }
853ŌåÆ
854ŌåÆ  // Create checkpoint commit in chain mode after QA passes
855ŌåÆ  if (success && chainMode && worktreePath) {
856ŌåÆ    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
857ŌåÆ  }
858ŌåÆ
859ŌåÆ  // Rebase onto the base branch before PR creation (unless --no-rebase)
860ŌåÆ  // This ensures the branch is up-to-date and prevents lockfile drift
861ŌåÆ  // AC-1: Non-chain mode rebases onto the base branch before PR
862ŌåÆ  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
863ŌåÆ  //        (intermediate branches must stay based on their predecessor)
864ŌåÆ  const shouldRebase =
865ŌåÆ    success &&
866ŌåÆ    worktreePath &&
867ŌåÆ    !options.noRebase &&
868ŌåÆ    (!chainMode || isLastInChain);
869ŌåÆ  if (shouldRebase) {
870ŌåÆ    rebaseBeforePR(
871ŌåÆ      worktreePath,
872ŌåÆ      issueNumber,
873ŌåÆ      packageManager,
874ŌåÆ      config.verbose,
875ŌåÆ      baseBranch,
876ŌåÆ    );
877ŌåÆ  }
878ŌåÆ
879ŌåÆ  // Create PR after successful QA + rebase (unless --no-pr)
880ŌåÆ  let prNumber: number | undefined;
881ŌåÆ  let prUrl: string | undefined;
882ŌåÆ  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
883ŌåÆ  if (shouldCreatePR) {
884ŌåÆ    const prResult = createPR(
885ŌåÆ      worktreePath,
886ŌåÆ      issueNumber,
887ŌåÆ      issueTitle,
888ŌåÆ      branch,
889ŌåÆ      config.verbose,
890ŌåÆ      labels,
891ŌåÆ    );
892ŌåÆ    if (prResult.success && prResult.prNumber && prResult.prUrl) {
893ŌåÆ      prNumber = prResult.prNumber;
894ŌåÆ      prUrl = prResult.prUrl;
895ŌåÆ
896ŌåÆ      // Update workflow state with PR info
897ŌåÆ      if (stateManager) {
898ŌåÆ        try {
899ŌåÆ          await stateManager.updatePRInfo(issueNumber, {
900ŌåÆ            number: prResult.prNumber,
901ŌåÆ            url: prResult.prUrl,
902ŌåÆ          });
903ŌåÆ        } catch {
904ŌåÆ          // State tracking errors shouldn't stop execution
905ŌåÆ        }
906ŌåÆ      }
907ŌåÆ    }
908ŌåÆ  }
909ŌåÆ
910ŌåÆ  return {
911ŌåÆ    issueNumber,
912ŌåÆ    success,
913ŌåÆ    phaseResults,
914ŌåÆ    durationSeconds,
915ŌåÆ    loopTriggered,
916ŌåÆ    prNumber,
917ŌåÆ    prUrl,
918ŌåÆ  };
919ŌåÆ}
920ŌåÆ

