import { StateManager } from './src/lib/workflow/state-manager.ts';

const issueBody = \`## Acceptance Criteria

- [ ] **AC-1:** \\\`sequant_run\\\` handler accepts \\\`extra._meta?.progressToken\\\` and uses \\\`extra.sendNotification()\\\` to emit \\\`notifications/progress\\\` at phase boundaries
- [ ] **AC-2:** stderr from the spawned process is consumed as a line stream (not buffered to completion) so progress events can be detected in real-time
- [ ] **AC-3:** Progress notifications include \\\`progress\\\` (phases completed), \\\`total\\\` (total expected phases), and \\\`message\\\` (human-readable status like \\\`\"#325: spec Ō£ō (45s)\"\\\`)
- [ ] **AC-4:** The spawn timeout resets on each progress notification sent, preventing timeout on long but progressing runs. A \\\`maxTotalTimeout\\\` ceiling (e.g. 2 hours) prevents infinite runs even with progress resets.
- [ ] **AC-5:** When no \\\`progressToken\\\` is provided by the client, behavior is identical to current implementation (full buffer, structured response at end) ŌĆö no breaking changes
- [ ] **AC-6:** Final structured response format (\\\`RunToolResponse\\\`) is unchanged ŌĆö progress notifications supplement, not replace, the final result
- [ ] **AC-7:** \\\`extra\\\` parameter typing updated from \\\`{ signal: AbortSignal }\\\` to use the full \\\`RequestHandlerExtra\\\` from the MCP SDK (includes \\\`_meta\\\`, \\\`sendNotification\\\`, \\\`signal\\\`)
- [ ] **AC-8:** The batch executor (\\\`src/lib/workflow/batch-executor.ts\\\`) emits \\\`SEQUANT_PROGRESS:{json}\\\` lines on stderr at each phase start, completion, and failure ŌĆö this is the source of progress events consumed by AC-2
- [ ] **AC-9:** The stdout/stderr parsing approach in the issue description uses the structured \\\`SEQUANT_PROGRESS:\\\` prefix (not PhaseSpinner regex) ŌĆö this is intentional to avoid fragile pattern matching against human-readable console output
- [ ] **AC-10:** Unit tests cover: progress notification emission with token, no-op when token absent, line buffer handling of partial chunks, timeout reset on progress, and \\\`SEQUANT_PROGRESS\\\` line parsing\`;

const ac = extractAcceptanceCriteria(issueBody);
console.log('Extracted AC:', JSON.stringify(ac, null, 2));

if (ac.items.length > 0) {
  const manager = new StateManager();
  (async () => {
    const existing = await manager.getIssueState(435);
    if (!existing) {
      await manager.initializeIssue(435, 'MCP: add progress notifications for sequant_run with graceful fallback');
    }
    await manager.updateAcceptanceCriteria(435, ac);
    console.log('AC stored in state for issue #435');
  })();
}
