 63ŌåÆ/**
 64ŌåÆ * Resolve the CLI binary path to avoid nested npx version mismatches (#389).
 65ŌåÆ *
 66ŌåÆ * Priority:
 67ŌåÆ * 1. process.argv[1] ŌĆö the script currently running (works for npx, global, local node)
 68ŌåÆ * 2. __dirname-relative resolution ŌĆö fallback for bundled/compiled entry points
 69ŌåÆ * 3. "npx" + "sequant" ŌĆö last resort if nothing else resolves
 70ŌåÆ *
 71ŌåÆ * Returns [command, prefixArgs] where the full invocation is:
 72ŌåÆ *   spawnAsync(command, [...prefixArgs, "run", ...userArgs])
 73ŌåÆ */
 74ŌåÆexport function resolveCliBinary(): [string, string[]] {
 75ŌåÆ  // Try process.argv ŌĆö most reliable across npx, global install, and local node
 76ŌåÆ  const nodeExe = process.argv[0];
 77ŌåÆ  const scriptPath = process.argv[1];
 78ŌåÆ
 79ŌåÆ  if (scriptPath && existsSync(scriptPath)) {
 80ŌåÆ    // If the entry point is a .ts file (e.g. running via `npx tsx bin/cli.ts serve`),
 81ŌåÆ    // the child process won't have tsx's loader hooks. Prefer the compiled dist output,
 82ŌåÆ    // or fall through to use tsx explicitly.
 83ŌåÆ    if (!scriptPath.endsWith(".ts")) {
 84ŌåÆ      return [nodeExe, [scriptPath]];
 85ŌåÆ    }
 86ŌåÆ
 87ŌåÆ    // Try compiled dist equivalent: bin/cli.ts ŌåÆ dist/bin/cli.js
 88ŌåÆ    const distPath = resolve(
 89ŌåÆ      dirname(scriptPath),
 90ŌåÆ      "..",
 91ŌåÆ      "dist",
 92ŌåÆ      "bin",
 93ŌåÆ      "cli.js",
 94ŌåÆ    );
 95ŌåÆ    if (existsSync(distPath)) {
 96ŌåÆ      return [process.execPath, [distPath]];
 97ŌåÆ    }
 98ŌåÆ
 99ŌåÆ    // Use tsx to run the .ts file directly
100ŌåÆ    return ["npx", ["tsx", scriptPath]];
101ŌåÆ  }
102ŌåÆ
103ŌåÆ  // Fallback: resolve relative to this file's location (dist/src/mcp/tools/run.js ŌåÆ dist/bin/cli.js)
104ŌåÆ  const cliPath = resolve(dirname(__dirname), "..", "..", "bin", "cli.js");
105ŌåÆ  if (existsSync(cliPath)) {
106ŌåÆ    return [process.execPath, [cliPath]];
107ŌåÆ  }
108ŌåÆ
109ŌåÆ  // Last resort: fall back to npx (original behavior)
110ŌåÆ  return ["npx", ["sequant"]];
111ŌåÆ}
