178ŌåÆexport function buildStructuredResponse(
179ŌåÆ  runLog: RunLog,
180ŌåÆ  rawOutput: string,
181ŌåÆ  overallStatus: "success" | "failure",
182ŌåÆ  exitCode?: number | null,
