185ŌåÆ  const issues: RunToolIssueSummary[] = runLog.issues.map((issue) => {
186ŌåÆ    // Find QA verdict from phase logs
187ŌåÆ    const qaPhase = issue.phases.find((p) => p.phase === "qa");
188ŌåÆ    const verdict = qaPhase?.verdict;
189ŌåÆ
190ŌåÆ    return {
191ŌåÆ      issueNumber: issue.issueNumber,
192ŌåÆ      status: issue.status,
193ŌåÆ      phases: issue.phases.map((p) => ({
194ŌåÆ        phase: p.phase,
195ŌåÆ        status: p.status,
196ŌåÆ        durationSeconds: p.durationSeconds,
197ŌåÆ      })),
198ŌåÆ      ...(verdict ? { verdict } : {}),
199ŌåÆ      durationSeconds: issue.totalDurationSeconds,
200ŌåÆ    };
201ŌåÆ  });
202ŌåÆ
203ŌåÆ  const phasesRan = [
204ŌåÆ    ...new Set(runLog.issues.flatMap((i) => i.phases.map((p) => p.phase))),
205ŌåÆ  ].join(",");
206ŌåÆ
207ŌåÆ  const response: RunToolResponse = {
208ŌåÆ    status: overallStatus,
209ŌåÆ    ...(exitCode != null && exitCode !== 0 ? { exitCode } : {}),
210ŌåÆ    issues,
211ŌåÆ    summary: {
212ŌåÆ      total: runLog.summary.totalIssues,
213ŌåÆ      passed: runLog.summary.passed,
214ŌåÆ      failed: runLog.summary.failed,
215ŌåÆ      durationSeconds: runLog.summary.totalDurationSeconds,
216ŌåÆ    },
217ŌåÆ    phases: phasesRan || runLog.config.phases.join(","),
218ŌåÆ    rawOutput: rawOutput.slice(-MAX_RAW_OUTPUT),
219ŌåÆ    ...(errorOutput ? { error: errorOutput.slice(-1000) } : {}),
220ŌåÆ  };
221ŌåÆ
222ŌåÆ  return enforceResponseSizeLimit(response);
223ŌåÆ}
