225ŌåÆ/**
226ŌåÆ * Enforce response size limit by progressively truncating rawOutput.
227ŌåÆ * Uses Buffer.byteLength for accurate UTF-8 byte measurement.
228ŌåÆ */
229ŌåÆfunction enforceResponseSizeLimit(response: RunToolResponse): RunToolResponse {
230ŌåÆ  let json = JSON.stringify(response);
231ŌåÆ  let byteLength = Buffer.byteLength(json, "utf-8");
232ŌåÆ
233ŌåÆ  if (byteLength <= MAX_RESPONSE_SIZE) {
234ŌåÆ    return response;
235ŌåÆ  }
236ŌåÆ
237ŌåÆ  // Progressively truncate rawOutput to fit
238ŌåÆ  const rawOutput = response.rawOutput || "";
239ŌåÆ  if (rawOutput.length > 0) {
240ŌåÆ    const excess = byteLength - MAX_RESPONSE_SIZE;
241ŌåÆ    // Over-trim slightly: multi-byte chars mean char count < byte count
242ŌåÆ    const newLength = Math.max(0, rawOutput.length - excess - 200);
243ŌåÆ
244ŌåÆ    response.rawOutput =
245ŌåÆ      newLength > 0 ? rawOutput.slice(-newLength) : undefined;
246ŌåÆ
247ŌåÆ    json = JSON.stringify(response);
248ŌåÆ    byteLength = Buffer.byteLength(json, "utf-8");
249ŌåÆ  }
250ŌåÆ
251ŌåÆ  // If still too large (structured data itself is huge), truncate error field
252ŌåÆ  if (byteLength > MAX_RESPONSE_SIZE && response.error) {
253ŌåÆ    const excess = byteLength - MAX_RESPONSE_SIZE;
254ŌåÆ    const newLength = Math.max(0, response.error.length - excess - 200);
255ŌåÆ    response.error =
256ŌåÆ      newLength > 0 ? response.error.slice(-newLength) : undefined;
257ŌåÆ  }
258ŌåÆ
259ŌåÆ  return response;
260ŌåÆ}
