355ŌåÆexport function registerRunTool(server: McpServer): void {
356ŌåÆ  server.registerTool(
357ŌåÆ    "sequant_run",
358ŌåÆ    {
359ŌåÆ      title: "Sequant Run",
360ŌåÆ      description:
361ŌåÆ        "Execute structured AI workflow phases for GitHub issues. " +
362ŌåÆ        "Runs spec (plan) ŌåÆ exec (implement) ŌåÆ qa (review) in sequence, creating worktrees and PRs. " +
363ŌåÆ        "Long-running: up to 30 minutes per issue. Returns structured JSON with per-issue phase results. " +
364ŌåÆ        "Check sequant_status first to avoid re-running completed issues. " +
365ŌåÆ        "Example: {issues: [123], phases: 'spec,exec'}",
366ŌåÆ      annotations: {
367ŌåÆ        readOnlyHint: false,
368ŌåÆ        destructiveHint: false,
369ŌåÆ        idempotentHint: false,
370ŌåÆ        openWorldHint: true,
371ŌåÆ      },
372ŌåÆ      inputSchema: runToolInputSchema,
373ŌåÆ    },
374ŌåÆ    (async (
375ŌåÆ      {
376ŌåÆ        issues,
377ŌåÆ        phases,
378ŌåÆ        qualityLoop,
379ŌåÆ        agent,
380ŌåÆ      }: {
381ŌåÆ        issues: number[];
382ŌåÆ        phases?: string;
383ŌåÆ        qualityLoop?: boolean;
384ŌåÆ        agent?: string;
385ŌåÆ      },
386ŌåÆ      extra: ToolHandlerExtra,
387ŌåÆ    ) => {
388ŌåÆ      if (!issues || issues.length === 0) {
389ŌåÆ        return {
390ŌåÆ          content: [
391ŌåÆ            {
392ŌåÆ              type: "text" as const,
393ŌåÆ              text: JSON.stringify({
394ŌåÆ                error: "INVALID_INPUT",
395ŌåÆ                message: "At least one issue number is required",
396ŌåÆ              }),
397ŌåÆ            },
398ŌåÆ          ],
399ŌåÆ          isError: true,
400ŌåÆ        };
401ŌåÆ      }
402ŌåÆ
403ŌåÆ      // Resolve CLI binary to avoid nested npx version mismatch (#389)
404ŌåÆ      const [command, prefixArgs] = resolveCliBinary();
405ŌåÆ
406ŌåÆ      // Build command arguments
407ŌåÆ      const args = [...prefixArgs, "run", ...issues.map(String)];
408ŌåÆ      if (phases) {
409ŌåÆ        args.push("--phases", phases);
410ŌåÆ      }
411ŌåÆ      if (qualityLoop) {
412ŌåÆ        args.push("--quality-loop");
413ŌåÆ      }
414ŌåÆ      if (agent) {
415ŌåÆ        args.push("--agent", agent);
416ŌåÆ      }
417ŌåÆ      args.push("--log-json");
418ŌåÆ
419ŌåÆ      const phasesStr = phases || "spec,exec,qa";
420ŌåÆ      const phaseList = phasesStr.split(",");
421ŌåÆ      const totalSteps = issues.length * phaseList.length;
422ŌåÆ      const runStartTime = new Date();
423ŌåÆ
424ŌåÆ      // Extract progress token for MCP progress notifications (AC-1)
425ŌåÆ      const progressToken = extra._meta?.progressToken;
426ŌåÆ
427ŌåÆ      // Track progress across phase transitions
428ŌåÆ      let currentStep = 0;
429ŌåÆ
430ŌåÆ      /**
431ŌåÆ       * Emit a progress notification if the client provided a progressToken.
432ŌåÆ       * Failures are caught to avoid aborting the run (AC-6).
433ŌåÆ       */
434ŌåÆ      const emitProgress = (event: ProgressEvent): void => {
435ŌåÆ        if (progressToken === undefined) return;
436ŌåÆ        currentStep++;
437ŌåÆ        try {
438ŌåÆ          // Fire-and-forget: don't await to avoid blocking the output stream
439ŌåÆ          void extra
440ŌåÆ            .sendNotification({
441ŌåÆ              method: "notifications/progress",
442ŌåÆ              params: {
443ŌåÆ                progressToken,
444ŌåÆ                progress: currentStep,
445ŌåÆ                total: totalSteps,
446ŌåÆ                message: `Issue #${event.issue}: ${event.phase} phase started (${currentStep}/${totalSteps})`,
447ŌåÆ              },
448ŌåÆ            })
449ŌåÆ            .catch(() => {
450ŌåÆ              // Swallow notification delivery errors (AC-6)
451ŌåÆ            });
452ŌåÆ        } catch {
453ŌåÆ          // Swallow synchronous errors (AC-6)
454ŌåÆ        }
455ŌåÆ      };
456ŌåÆ
457ŌåÆ      /**
458ŌåÆ       * Handle a complete line of subprocess stderr, checking for progress events.
459ŌåÆ       * The batch executor emits SEQUANT_PROGRESS:{json} lines at each phase start.
460ŌåÆ       */
461ŌåÆ      const handleLine = (line: string): void => {
462ŌåÆ        const event = parseProgressLine(line);
463ŌåÆ        if (event) emitProgress(event);
464ŌåÆ      };
465ŌåÆ
466ŌåÆ      // Line-buffer stderr to handle chunk boundaries correctly
467ŌåÆ      const stderrLineBuffer =
468ŌåÆ        progressToken !== undefined ? createLineBuffer(handleLine) : undefined;
469ŌåÆ
470ŌåÆ      // Register all issues as active runs for real-time status polling
471ŌåÆ      for (const issue of issues) {
472ŌåÆ        registerRun(issue);
473ŌåÆ      }
474ŌåÆ
475ŌåÆ      try {
476ŌåÆ        const result = await spawnAsync(command, args, {
477ŌåÆ          timeout: 1800000, // 30 min default
478ŌåÆ          env: {
479ŌåÆ            ...process.env,
480ŌåÆ            SEQUANT_ORCHESTRATOR: "mcp-server",
481ŌåÆ          },
482ŌåÆ          signal: extra.signal,
483ŌåÆ          onStderr: stderrLineBuffer,
484ŌåÆ        });
485ŌåÆ
486ŌåÆ        const stdout = result.stdout || "";
487ŌåÆ        const stderr = result.stderr || "";
