489ŌåÆ          result.exitCode === 0 ? "success" : "failure";
490ŌåÆ
491ŌåÆ        // Try to read structured log file for rich per-issue data
492ŌåÆ        const runLog = await readLatestRunLog(runStartTime);
493ŌåÆ
494ŌåÆ        let response: RunToolResponse;
495ŌåÆ        if (runLog) {
496ŌåÆ          response = buildStructuredResponse(
497ŌåÆ            runLog,
498ŌåÆ            stdout,
499ŌåÆ            overallStatus,
500ŌåÆ            result.exitCode,
501ŌåÆ            stderr || undefined,
502ŌåÆ          );
503ŌåÆ        } else {
504ŌåÆ          // Fallback: no log file available
505ŌåÆ          response = buildFallbackResponse(
506ŌåÆ            stdout,
507ŌåÆ            issues,
508ŌåÆ            overallStatus,
509ŌåÆ            phasesStr,
510ŌåÆ            result.exitCode,
511ŌåÆ            stderr || undefined,
512ŌåÆ          );
513ŌåÆ        }
514ŌåÆ
515ŌåÆ        return {
516ŌåÆ          content: [
517ŌåÆ            {
518ŌåÆ              type: "text" as const,
519ŌåÆ              text: JSON.stringify(response),
520ŌåÆ            },
521ŌåÆ          ],
522ŌåÆ          ...(result.exitCode !== 0 ? { isError: true } : {}),
523ŌåÆ        };
524ŌåÆ      } catch (error) {
525ŌåÆ        return {
526ŌåÆ          content: [
527ŌåÆ            {
528ŌåÆ              type: "text" as const,
529ŌåÆ              text: JSON.stringify({
530ŌåÆ                error: "EXECUTION_ERROR",
531ŌåÆ                message: error instanceof Error ? error.message : String(error),
532ŌåÆ              }),
533ŌåÆ            },
534ŌåÆ          ],
535ŌåÆ          isError: true,
536ŌåÆ        };
537ŌåÆ      } finally {
538ŌåÆ        for (const issue of issues) {
539ŌåÆ          unregisterRun(issue);
540ŌåÆ        }
541ŌåÆ      }
542ŌåÆ    }) as Parameters<typeof server.registerTool>[2],
543ŌåÆ  );
544ŌåÆ}
