  env?: NodeJS.ProcessEnv;
  signal?: AbortSignal;
  /** Called with each stderr chunk (real-time, before process exits) */
  onStderr?: (chunk: string) => void;
  /** Called with each stdout chunk (real-time, before process exits) */
  onStdout?: (chunk: string) => void;
  /**
   * Called when a progress event is detected.
   * Resets the per-phase timeout to prevent premature kills on long-running
   * but progressing runs. The MAX_TOTAL_TIMEOUT ceiling still applies.
   */
  onProgress?: () => void;
}

