it("should kill process after timeout with no progress", async () => {
  // Use a very short timeout for testing
  await expect(
    spawnAsync("sleep", ["10"], {
      timeout: 100, // 100ms timeout
    }),
  ).rejects.toThrow("Process timed out after 100ms");
});

it("should reset timeout when onProgress is called", async () => {
  let progressCalls = 0;

  // This process writes to stderr every 50ms and runs for 200ms
  // With 150ms timeout and progress resets, it should succeed
  const result = await spawnAsync(
    "bash",
    [
      "-c",
      'for i in 1 2 3 4; do echo "SEQUANT_PROGRESS:{}" >&2; sleep 0.05; done; echo done',
    ],
    {
      timeout: 150,
      onProgress: () => {
        progressCalls++;
      },
      onStderr: () => {
        // stderr is being consumed
      },
    },
  );

  expect(result.exitCode).toBe(0);
  expect(result.stdout.trim()).toBe("done");
  // onProgress was mutated by spawnAsync to add timeout reset,
  // but the original callback still fires
  expect(progressCalls).toBeGreaterThan(0);
});

it("should respect MAX_TOTAL_TIMEOUT even with progress resets", async () => {
  // With onProgress set, maxTotal = MAX_TOTAL_TIMEOUT (2 hours)
  // This test verifies the timeout message mentions progress when onProgress is set
  await expect(
    spawnAsync("sleep", ["10"], {
      timeout: 50,
      onProgress: () => {},
    }),
  ).rejects.toThrow("no progress for 50ms");

