 42ŌåÆ/** Create a mock ChildProcess that emits events asynchronously */
 43ŌåÆfunction createMockProcess(opts: {
 44ŌåÆ  exitCode?: number | null;
 45ŌåÆ  stdout?: string;
 46ŌåÆ  stderr?: string;
 47ŌåÆ  stderrChunks?: string[];
 48ŌåÆ  stdoutChunks?: string[];
 49ŌåÆ  error?: Error;
 50ŌåÆ  delay?: number;
 51ŌåÆ}) {
 52ŌåÆ  const proc = new EventEmitter() as ReturnType<typeof spawn>;
 53ŌåÆ  const stdoutEmitter = new EventEmitter();
 54ŌåÆ  const stderrEmitter = new EventEmitter();
 55ŌåÆ  (proc as unknown as Record<string, unknown>).stdout = stdoutEmitter;
 56ŌåÆ  (proc as unknown as Record<string, unknown>).stderr = stderrEmitter;
 57ŌåÆ  (proc as unknown as Record<string, unknown>).pid = 12345;
 58ŌåÆ  (proc as unknown as Record<string, unknown>).killed = false;
 59ŌåÆ  (proc as unknown as Record<string, unknown>).kill = vi.fn(() => {
 60ŌåÆ    (proc as unknown as Record<string, unknown>).killed = true;
 61ŌåÆ  });
 62ŌåÆ
 63ŌåÆ  const emit = () => {
 64ŌåÆ    if (opts.stdoutChunks) {
 65ŌåÆ      for (const chunk of opts.stdoutChunks) {
 66ŌåÆ        stdoutEmitter.emit("data", Buffer.from(chunk));
 67ŌåÆ      }
 68ŌåÆ    } else if (opts.stdout) {
 69ŌåÆ      stdoutEmitter.emit("data", Buffer.from(opts.stdout));
 70ŌåÆ    }
 71ŌåÆ    if (opts.stderrChunks) {
 72ŌåÆ      for (const chunk of opts.stderrChunks) {
 73ŌåÆ        stderrEmitter.emit("data", Buffer.from(chunk));
 74ŌåÆ      }
 75ŌåÆ    } else if (opts.stderr) {
 76ŌåÆ      stderrEmitter.emit("data", Buffer.from(opts.stderr));
 77ŌåÆ    }
 78ŌåÆ    if (opts.error) {
 79ŌåÆ      proc.emit("error", opts.error);
 80ŌåÆ    } else {
 81ŌåÆ      proc.emit("close", opts.exitCode ?? 0);
 82ŌåÆ    }
 83ŌåÆ  };
 84ŌåÆ
 85ŌåÆ  if (opts.delay) {
 86ŌåÆ    setTimeout(emit, opts.delay);
 87ŌåÆ  } else {
 88ŌåÆ    queueMicrotask(emit);
 89ŌåÆ  }
 90ŌåÆ
 91ŌåÆ  return proc;
 92ŌåÆ}
