  });

  describe("AC-3: Progress total = issue count ├Ś phase count", () => {
    it("should calculate total as 6 for 2 issues ├Ś 3 default phases", async () => {
      const progressEvents: ProgressNotification[] = [];

      mockedSpawn.mockImplementation(() =>
        createMockProcess({
          exitCode: 0,
          stderrChunks: [progressLine(100, "spec")],
        }),
      );

      await client.callTool(
        { name: "sequant_run", arguments: { issues: [100, 200] } },
