it("should reset timeout when SEQUANT_PROGRESS lines arrive on stderr", async () => {
  let progressCalls = 0;

  // This process emits SEQUANT_PROGRESS lines on stderr every 50ms
  // and runs for ~200ms total. With a 150ms timeout and progress
  // resets, it should complete successfully instead of timing out.
  const result = await spawnAsync(
    "bash",
    [
      "-c",
      'for i in 1 2 3 4; do echo "SEQUANT_PROGRESS:{\"issue\":1,\"phase\":\"spec\",\"event\":\"start\"}" >&2; sleep 0.05; done; echo done',
    ],
    {
      timeout: 150,
      onProgress: () => {
        progressCalls++;
      },
    },
  );

  expect(result.exitCode).toBe(0);
  expect(result.stdout.trim()).toBe("done");
  // spawnAsync detects progress lines internally and calls onProgress
  expect(progressCalls).toBeGreaterThan(0);
});

