/**
 * Integration tests for MCP Progress Notifications (#421)
 *
 * Tests AC-2 (phase transition ŌåÆ progress notification flow),
 * AC-5 (backward compatibility with existing behavior),
 * and error scenarios.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { EventEmitter } from "events";
import { spawn } from "child_process";

// Mock child_process before importing server
vi.mock("child_process", async (importOriginal) => {
  const actual = await importOriginal<typeof import("child_process")>();
  return {
    ...actual,
    spawn: vi.fn(),
  };
});

// Mock fs so resolveCliBinary falls through to npx fallback
vi.mock("fs", async (importOriginal) => {
  const actual = await importOriginal<typeof import("fs")>();
  return {
    ...actual,
    existsSync: vi.fn(() => false),
  };
});

vi.mock("fs/promises", async (importOriginal) => {
  const actual = await importOriginal<typeof import("fs/promises")>();
  return {
    ...actual,
    readdir: vi.fn(() => Promise.resolve([])),
    readFile: vi.fn(() => Promise.resolve("")),
  };
});

const mockedSpawn = vi.mocked(spawn);

/** Progress event from onprogress callback */
interface ProgressNotification {
  progress: number;
  total: number;
  message?: string;
}

/** Helper: build a SEQUANT_PROGRESS line as the batch executor emits it */
function progressLine(
  issue: number,
  phase: string,
  event: "start" | "complete" | "failed" = "start",
  extra?: { durationSeconds?: number; error?: string },
): string {
  const payload: Record<string, unknown> = { issue, phase, event };
  if (extra?.durationSeconds !== undefined)
    payload.durationSeconds = extra.durationSeconds;
  if (extra?.error !== undefined) payload.error = extra.error;
  return `SEQUANT_PROGRESS:${JSON.stringify(payload)}\n`;
}

/** Create a mock ChildProcess with controllable stderr chunks for progress simulation */
function createMockProcessWithPhaseOutput(opts: {
  exitCode?: number | null;
  stdout?: string;
  stdoutChunks?: string[];
  stderrChunks?: string[];
}) {
  const proc = new EventEmitter() as ReturnType<typeof spawn>;
